class Solution {
public:
    vector<long long> maximumEvenSplit(long long finalSum) {
        vector<long long> result;
        for (long long i = 2; i <= finalSum; i += 2) {
            if (finalSum >= i) {
                result.push_back(i);
                finalSum -= i;
            }
        }
        return result;
    }
};
